const CONSUMER_KEY    = $vars['ETRADE_CONSUMER_KEY'];
const CONSUMER_SECRET = $vars['ETRADE_CONSUMER_SECRET'];
const ACCESS_TOKEN    = $vars['ETRADE_ACCESS_TOKEN'];
const ACCESS_TOKEN_SECRET = $vars['ETRADE_ACCESS_TOKEN_SECRET'];
const N8N_API_KEY     = $vars['N8N_API_KEY'];
const N8N_BASE        = 'https://ashes2echoes.app.n8n.cloud';
const crypto = require('crypto');
function pct(s) { return encodeURIComponent(String(s)); }
function buildOAuthHeader(method, baseUrl, extraParams, token, tokenSecret) {
  const ts = String(Math.floor(Date.now()/1000));
  const nonce = Math.random().toString(36).substring(2)+Math.random().toString(36).substring(2);
  const params = { oauth_consumer_key:CONSUMER_KEY, oauth_nonce:nonce, oauth_signature_method:'HMAC-SHA1', oauth_timestamp:ts, oauth_token:token, oauth_version:'1.0', ...(extraParams||{}) };
  const sortedStr = Object.keys(params).sort().map(k=>pct(k)+'='+pct(params[k])).join('&');
  const baseStr = method.toUpperCase()+'&'+pct(baseUrl)+'&'+pct(sortedStr);
  const sigKey = pct(CONSUMER_SECRET)+'&'+pct(tokenSecret);
  const sig = crypto.createHmac('sha1',sigKey).update(baseStr).digest('base64');
  const allWithSig = {...params, oauth_signature:sig};
  return 'OAuth realm="",' + Object.keys(allWithSig).filter(k=>k.startsWith('oauth_')).sort().map(k=>k+'="'+pct(allWithSig[k])+'"').join(',');
}
async function updateVariable(key, value) {
  const vars = await this.helpers.httpRequest({method:'GET',url:N8N_BASE+'/api/v1/variables',headers:{'X-N8N-API-KEY':N8N_API_KEY}});
  const varObj = (vars.data||[]).find(v=>v.key===key);
  if(!varObj) return false;
  try { await this.helpers.httpRequest({method:'PATCH',url:N8N_BASE+'/api/v1/variables/'+varObj.id,headers:{'X-N8N-API-KEY':N8N_API_KEY,'Content-Type':'application/json'},body:JSON.stringify({key,value})}); return true; } catch(e) { return false; }
}
const RENEW_URL = 'https://api.etrade.com/oauth/renew_access_token';
const renewHeader = buildOAuthHeader('GET',RENEW_URL,{},ACCESS_TOKEN,ACCESS_TOKEN_SECRET);
let renewResult = 'UNKNOWN';
try {
  const renewResp = await this.helpers.httpRequest({method:'GET',url:RENEW_URL,headers:{'Authorization':renewHeader},returnFullResponse:true,ignoreHttpStatusErrors:true});
  renewResult = renewResp.statusCode===200 ? 'RENEWED' : 'FAILED_'+renewResp.statusCode;
} catch(e) { renewResult = 'ERROR_'+e.message; }
if (renewResult === 'RENEWED') return [{json:{status:'RENEWED',message:'Token renewed successfully',timestamp:new Date().toISOString()}}];
const REQ_URL = 'https://api.etrade.com/oauth/request_token';
const reqTs = String(Math.floor(Date.now()/1000));
const reqNonce = Math.random().toString(36).substring(2)+Math.random().toString(36).substring(2);
const reqParams = {oauth_callback:'oob',oauth_consumer_key:CONSUMER_KEY,oauth_nonce:reqNonce,oauth_signature_method:'HMAC-SHA1',oauth_timestamp:reqTs,oauth_version:'1.0'};
const reqSorted = Object.keys(reqParams).sort().map(k=>pct(k)+'='+pct(reqParams[k])).join('&');
const reqBase = 'GET&'+pct(REQ_URL)+'&'+pct(reqSorted);
const reqSigKey = pct(CONSUMER_SECRET)+'&';
const reqSig = crypto.createHmac('sha1',reqSigKey).update(reqBase).digest('base64');
reqParams['oauth_signature'] = reqSig;
const reqHeader = 'OAuth realm="",' + Object.keys(reqParams).filter(k=>k.startsWith('oauth_')).sort().map(k=>k+'="'+pct(reqParams[k])+'"').join(',');
try {
  const rtResp = await this.helpers.httpRequest({method:'GET',url:REQ_URL,headers:{'Authorization':reqHeader}});
  const parsed = {};
  String(rtResp).split('&').forEach(p=>{const[k,v]=p.split('=');parsed[k]=decodeURIComponent(v||'');});
  const requestToken = parsed['oauth_token']||'';
  if(!requestToken) return [{json:{status:'ERROR',error:'Request token empty',renewResult,rawResponse:String(rtResp).substring(0,200),timestamp:new Date().toISOString()}}];
  await updateVariable.call(this,'ETRADE_REQUEST_TOKEN',requestToken);
  await updateVariable.call(this,'ETRADE_REQUEST_TOKEN_SECRET',parsed['oauth_token_secret']||'');
  const authUrl = 'https://us.etrade.com/e/t/etws/authorize?key='+CONSUMER_KEY+'&token='+encodeURIComponent(requestToken);
  return [{json:{status:'AUTH_REQUIRED',request_token:requestToken,request_token_secret:parsed['oauth_token_secret']||'',auth_url:authUrl,renewResult,timestamp:new Date().toISOString()}}];
} catch(e) { return [{json:{status:'ERROR',error:e.message,renewResult}}]; }

